//! elementwise kernel family — Phase 2. Flat C ABI per contracts/wasm-abi.md §9.
//! Owned by the Phase-2 elementwise agent; other agents do not edit this file.
//!
//! All arithmetic is data-only (no validity pointers) per ABI §8. Null
//! propagation for binary ops is the expression-compiler's responsibility via
//! `validity_and`. SIMD paths are gated by `#[cfg(target_feature = "simd128")]`;
//! both scalar and SIMD builds produce bit-identical results for elementwise ops.
//!
//! Integer arithmetic wraps (two's complement). Integer div/mod by zero writes
//! 0 (or any value) and does NOT trap (ABI §7). Float div/mod follows IEEE-754.
//! Comparison kernels produce Arrow-LSB bitmasks (1 bit/element, §4.2).
//! Padding bits beyond `len` in the final mask byte are always written as 0.

// ========================================================================
// SIMD imports (excluded on non-simd128 targets by cfg)
// ========================================================================
#[cfg(target_feature = "simd128")]
use core::arch::wasm32::v128;

// ========================================================================
// Utility: write `n_bytes` zero bytes starting at `ptr`
// ========================================================================
#[inline(always)]
unsafe fn zero_bytes(ptr: *mut u8, n_bytes: usize) {
    for k in 0..n_bytes {
        *ptr.add(k) = 0;
    }
}

// ========================================================================
// Utility: read one validity bit (returns 0 or 1 as u8)
// vp_ptr == 0 means all-valid; returns 1.
// ========================================================================
#[inline(always)]
unsafe fn vbit(vp_ptr: *const u8, idx: usize) -> u8 {
    if vp_ptr.is_null() {
        1
    } else {
        (*vp_ptr.add(idx >> 3) >> (idx & 7)) & 1
    }
}

// ========================================================================
// MACRO: binary float arithmetic with SIMD (f64x2 or f32x4)
// ========================================================================

macro_rules! float64_bin {
    ($fn_name:ident, $op:tt, $simd_op:ident) => {
        #[no_mangle]
        pub unsafe extern "C" fn $fn_name(
            a: *const f64,
            b: *const f64,
            out: *mut f64,
            len: u32,
        ) {
            let n = len as usize;
            let mut i = 0usize;
            #[cfg(target_feature = "simd128")]
            {
                while i + 2 <= n {
                    core::arch::wasm32::v128_store(
                        out.add(i) as *mut v128,
                        core::arch::wasm32::$simd_op(
                            core::arch::wasm32::v128_load(a.add(i) as *const v128),
                            core::arch::wasm32::v128_load(b.add(i) as *const v128),
                        ),
                    );
                    i += 2;
                }
            }
            while i < n {
                *out.add(i) = *a.add(i) $op *b.add(i);
                i += 1;
            }
        }
    };
}

