// ========================================================================
// § Kleene three-valued boolean logic (dtypes.md §4.2)
//
// Bool data is u8 (0 or 1 per element); vp_ptr=0 means all-valid.
//
// AND Kleene: F dominates → F&N=F (valid,0); N&N=N; T&N=N
//   out_valid = (av & bv) | (av & ~ad) | (bv & ~bd)
//   out_data  = ad & bd
//
// OR Kleene: T dominates → T|N=T (valid,1); N|N=N; F|N=N
//   out_valid = (av & bv) | (av & ad) | (bv & bd)
//   out_data  = ad | bd
// ========================================================================

#[no_mangle]
pub unsafe extern "C" fn and_kleene(
    a_ptr: *const u8,
    a_vp:  *const u8,
    b_ptr: *const u8,
    b_vp:  *const u8,
    out_ptr: *mut u8,
    out_vp:  *mut u8,
    len: u32,
) {
    let n = len as usize;
    let nbytes = n.div_ceil(8);
    zero_bytes(out_vp, nbytes);

    for i in 0..n {
        let av = vbit(a_vp, i);
        let bv = vbit(b_vp, i);
        let ad = *a_ptr.add(i) & 1;
        let bd = *b_ptr.add(i) & 1;

        // valid when: both valid, OR a is valid-false, OR b is valid-false
        let out_valid = (av & bv) | (av & (ad ^ 1)) | (bv & (bd ^ 1));
        let out_data  = ad & bd;

        *out_ptr.add(i) = out_data;
        if out_valid != 0 {
            *out_vp.add(i >> 3) |= 1u8 << (i & 7);
        }
    }
}

#[no_mangle]
pub unsafe extern "C" fn or_kleene(
    a_ptr: *const u8,
    a_vp:  *const u8,
    b_ptr: *const u8,
    b_vp:  *const u8,
    out_ptr: *mut u8,
    out_vp:  *mut u8,
    len: u32,
) {
    let n = len as usize;
    let nbytes = n.div_ceil(8);
    zero_bytes(out_vp, nbytes);

    for i in 0..n {
        let av = vbit(a_vp, i);
        let bv = vbit(b_vp, i);
        let ad = *a_ptr.add(i) & 1;
        let bd = *b_ptr.add(i) & 1;

        // valid when: both valid, OR a is valid-true, OR b is valid-true
        let out_valid = (av & bv) | (av & ad) | (bv & bd);
        let out_data  = ad | bd;

        *out_ptr.add(i) = out_data;
        if out_valid != 0 {
            *out_vp.add(i >> 3) |= 1u8 << (i & 7);
        }
    }
}

/// NOT bool: ¬T=F, ¬F=T, ¬N=N (validity propagates unchanged).
#[no_mangle]
pub unsafe extern "C" fn not_bool(
    a_ptr: *const u8,
    a_vp:  *const u8,
    out_ptr: *mut u8,
    out_vp:  *mut u8,
    len: u32,
) {
    let n = len as usize;
    let nbytes = n.div_ceil(8);
    zero_bytes(out_vp, nbytes);

    for i in 0..n {
        let av = vbit(a_vp, i);
        let ad = *a_ptr.add(i) & 1;
        *out_ptr.add(i) = ad ^ 1; // flip: 0→1, 1→0
        if av != 0 {
            *out_vp.add(i >> 3) |= 1u8 << (i & 7);
        }
    }
}

// ========================================================================
// § Validity bitmap ops (byte-level AND/OR; no element-level validity)
// ========================================================================

/// Pointwise AND of two validity bitmaps. `len` is the element count.
/// Both inputs and output are `ceil(len/8)` bytes, Arrow-LSB.
#[no_mangle]
pub unsafe extern "C" fn validity_and(
    a_vp: *const u8,
    b_vp: *const u8,
    out_vp: *mut u8,
    len: u32,
) {
    let nbytes = (len as usize).div_ceil(8);
    for k in 0..nbytes {
        *out_vp.add(k) = *a_vp.add(k) & *b_vp.add(k);
    }
}

/// Pointwise OR of two validity bitmaps.
#[no_mangle]
pub unsafe extern "C" fn validity_or(
    a_vp: *const u8,
    b_vp: *const u8,
    out_vp: *mut u8,
    len: u32,
) {
    let nbytes = (len as usize).div_ceil(8);
    for k in 0..nbytes {
        *out_vp.add(k) = *a_vp.add(k) | *b_vp.add(k);
    }
}

// ========================================================================
// § Cast functions — full matrix from dtypes.md §2
//
// Signature: cast_<from>_<to>(in_ptr, in_vp, out_ptr, out_vp, len)
// in_vp == 0 → all-valid fast path (no null in input).
// out_vp is always written (both null-propagated and range-failure bits).
// ========================================================================

// ---- f64 casts ----

/// f64 → f32: ≈ (round; overflow → ±Inf, not null). Null propagates.
#[no_mangle]
pub unsafe extern "C" fn cast_f64_f32(
    inp: *const f64, in_vp: *const u8,
    out: *mut f32,   out_vp: *mut u8,
    len: u32,
) {
    let n = len as usize;
    zero_bytes(out_vp, n.div_ceil(8));
    for i in 0..n {
        if vbit(in_vp, i) != 0 {
            *out.add(i) = *inp.add(i) as f32;
            *out_vp.add(i >> 3) |= 1u8 << (i & 7);
        } else {
            *out.add(i) = 0.0;
        }
    }
}

/// f64 → i32: ⚠ trunc toward 0; out-of-range or NaN → null.
#[no_mangle]
pub unsafe extern "C" fn cast_f64_i32(
    inp: *const f64, in_vp: *const u8,
    out: *mut i32,   out_vp: *mut u8,
    len: u32,
) {
    let n = len as usize;
    zero_bytes(out_vp, n.div_ceil(8));
    for i in 0..n {
        if vbit(in_vp, i) == 0 {
            *out.add(i) = 0;
            continue;
        }
        let v = *inp.add(i);
        // In-range: v > -2^31 - 1 (i.e. trunc(v) >= -2^31) AND v < 2^31
        // We use: v > -2147483649.0 && v < 2147483648.0
        // NaN and ±Inf are excluded by the comparisons (NaN compares false).
        if v > -2_147_483_649.0_f64 && v < 2_147_483_648.0_f64 {
            *out.add(i) = v as i32;
            *out_vp.add(i >> 3) |= 1u8 << (i & 7);
        } else {
            *out.add(i) = 0;
        }
    }
}

/// f64 → u32: ⚠ trunc toward 0; negative, out-of-range, or NaN → null.
#[no_mangle]
pub unsafe extern "C" fn cast_f64_u32(
    inp: *const f64, in_vp: *const u8,
    out: *mut u32,   out_vp: *mut u8,
    len: u32,
) {
    let n = len as usize;
    zero_bytes(out_vp, n.div_ceil(8));
    for i in 0..n {
        if vbit(in_vp, i) == 0 {
            *out.add(i) = 0;
            continue;
        }
        let v = *inp.add(i);
        // In-range: v >= 0 && v < 2^32 = 4294967296.0
        // NaN and negative values excluded by the first comparison.
        if (0.0_f64..4_294_967_296.0_f64).contains(&v) {
            *out.add(i) = v as u32;
            *out_vp.add(i >> 3) |= 1u8 << (i & 7);
        } else {
            *out.add(i) = 0;
        }
    }
}

/// f64 → bool: x≠0→true, 0→false, NaN→null. Null propagates.
#[no_mangle]
pub unsafe extern "C" fn cast_f64_bool(
    inp: *const f64, in_vp: *const u8,
    out: *mut u8,    out_vp: *mut u8,
    len: u32,
) {
    let n = len as usize;
    zero_bytes(out_vp, n.div_ceil(8));
    for i in 0..n {
        if vbit(in_vp, i) == 0 {
            *out.add(i) = 0;
            continue;
        }
        let v = *inp.add(i);
        if v.is_nan() {
            // NaN → null
            *out.add(i) = 0;
        } else {
            *out.add(i) = if v != 0.0 { 1 } else { 0 };
            *out_vp.add(i >> 3) |= 1u8 << (i & 7);
        }
    }
}

