/// i32 → f64: = (exact). Null propagates.
#[no_mangle]
pub unsafe extern "C" fn cast_i32_f64(
    inp: *const i32, in_vp: *const u8,
    out: *mut f64,   out_vp: *mut u8,
    len: u32,
) {
    let n = len as usize;
    zero_bytes(out_vp, n.div_ceil(8));
    for i in 0..n {
        if vbit(in_vp, i) != 0 {
            *out.add(i) = *inp.add(i) as f64;
            *out_vp.add(i >> 3) |= 1u8 << (i & 7);
        } else {
            *out.add(i) = 0.0;
        }
    }
}

